-- ======================== 批量生成更多溯源数据 ========================
-- 为了模拟真实场景，生成大量数据

-- 批次1: 电机类产品 (TC-2026010003 ~ TC-2026010012)

-- 批次2: 传感器类产品 (TC-2026010011 ~ TC-2026010025)

-- 批次3: 管件类产品 (TC-2026010021 ~ TC-2026010040)

-- 批次4: 阀门类产品 - 华东区域 (TC-2026010031 ~ TC-2026010050)

-- 批次5: 轴承类产品 - 东北区域 (TC-2026010041 ~ TC-2026010060)

-- 批次6: 更多阀门和管件 - 西南区域 (TC-2026010051 ~ TC-2026010070)

-- 批次7: 华北区域补充 (TC-2026010061 ~ TC-2026010080)

-- 批次8: 华南区域补充 (TC-2026010071 ~ TC-2026010090)

-- 批次9: 西北区域 (TC-2026010081 ~ TC-2026010095)

-- 批次10: 最近一周数据 (TC-2026010091 ~ TC-2026010100)

-- ==================== 3. 生成对应的快照记录 ====================
-- 为每个溯源码生成快照（取最新状态）

SELECT 
    t.trace_code,
    t.spu_id,
    CASE t.action_type
        WHEN 'INIT' THEN '已生产'
        WHEN 'INBOUND' THEN '已入库'
        WHEN 'OUTBOUND' THEN '已出库'
        WHEN 'TRANSFER' THEN '运输中'
        WHEN 'EXCEPTION' THEN '异常'
        WHEN 'CORRECTION' THEN '已修正'
    END AS current_status,
    COALESCE(t.to_node, t.from_node) AS current_node,
    t.operator AS current_owner,
    t.province,
    t.city,
    t.event_time AS last_event_time,
    t.id AS last_log_id,
    t.current_hash AS last_hash,
    0 AS version
FROM trace_lifecycle_log t
INNER JOIN (
    SELECT trace_code, MAX(id) AS max_id
    FROM trace_lifecycle_log
    WHERE trace_code NOT IN ('TC-2026010001', 'TC-2026010002')  -- 排除已手动插入的
    GROUP BY trace_code
) latest ON t.trace_code = latest.trace_code AND t.id = latest.max_id;

SET FOREIGN_KEY_CHECKS = 1;

